module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [3:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] temp[0:7];
reg [15:0] sum[0:3];
reg [15:0] mul_out_reg;
always@(posedge clk or negedge rst_n)begin
	if(!rst_n)begin
		mul_en_out_reg <= 4'd0;
	end
	else begin
		mul_en_out_reg <= {mul_en_out_reg[2:0],mul_en_in};
	end
end
always@(posedge clk or negedge rst_n)begin
	if(!rst_n)begin
		mul_a_reg <= 8'd0;
		mul_b_reg <= 8'd0;
	end
	else begin
		if(mul_en_in==1'b1)begin
			mul_a_reg <= mul_a;
			mul_b_reg <= mul_b;
		end
		else begin
			mul_a_reg <= 8'd0;
			mul_b_reg <= 8'd0;
		end
	end
end
always@(*)begin
	temp[0] = mul_b_reg[0]?{8'd0,mul_a_reg}:16'd0;
	temp[1] = mul_b_reg[1]?{7'd0,mul_a_reg,1'd0}:16'd0;
	temp[2] = mul_b_reg[2]?{6'd0,mul_a_reg,2'd0}:16'd0;
	temp[3] = mul_b_reg[3]?{5'd0,mul_a_reg,3'd0}:16'd0;
	temp[4] = mul_b_reg[4]?{4'd0,mul_a_reg,4'd0}:16'd0;
	temp[5] = mul_b_reg[5]?{3'd0,mul_a_reg,5'd0}:16'd0;
	temp[6] = mul_b_reg[6]?{2'd0,mul_a_reg,6'd0}:16'd0;
	temp[7] = mul_b_reg[7]?{1'd0,mul_a_reg,7'd0}:16'd0;
end
always@(posedge clk or negedge rst_n)begin
	if(!rst_n)begin
		sum[0] <= 16'd0;
		sum[1] <= 16'd0;
		sum[2] <= 16'd0;
		sum[3] <= 16'd0;
	end
	else begin
		sum[0] <= temp[0]+temp[1];
		sum[1] <= temp[2]+temp[3];
		sum[2] <= temp[4]+temp[5];
		sum[3] <= temp[6]+temp[7];
	end
end
always@(posedge clk or negedge rst_n)begin
	if(!rst_n)begin
		mul_out_reg <= 16'd0;
	end
	else begin
		mul_out_reg <= sum[0]+sum[1]+sum[2]+sum[3];
	end
end
assign mul_en_out = mul_en_out_reg[3];
assign mul_out = mul_en_out?mul_out_reg:16'd0;
endmodule
